// ======================================================
// AGRUPA PACIENTES PELO NOME
// RETORNA QUANTIDADE DE EXAMES E LISTA DE EXAMES
// ======================================================

const itens = $input.all().map(item => item.json);

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/\s+/g, " ")
    .trim();
}

const mapaPacientes = new Map();

for (const item of itens) {
  const pacienteOriginal = String(item.Paciente || "").trim();

  if (!pacienteOriginal) continue;

  const chavePaciente = normalizarTexto(pacienteOriginal);

  const exame = String(item.Exame || "").trim();

  if (!mapaPacientes.has(chavePaciente)) {
    mapaPacientes.set(chavePaciente, {
      nomeRelatorio: item.nomeRelatorio || "",
      dataRelatorio: item.dataRelatorio || "",
      dataCadastro: item.dataCadastro || "",
      Paciente: pacienteOriginal,
      pacienteNormalizado: chavePaciente,
      exames: [],
      linhasOriginais: [],
      registros: []
    });
  }

  const paciente = mapaPacientes.get(chavePaciente);

  if (exame) {
    paciente.exames.push(exame);
  }

  paciente.linhasOriginais.push(item.row_number_original || item.row_number || "");

  paciente.registros.push(item);
}

const resultado = [];

for (const paciente of mapaPacientes.values()) {
  resultado.push({
    json: {
      nomeRelatorio: paciente.nomeRelatorio,
      dataRelatorio: paciente.dataRelatorio,
      dataCadastro: paciente.dataCadastro,

      Paciente: paciente.Paciente,
      pacienteNormalizado: paciente.pacienteNormalizado,

      quantidadeExames: paciente.exames.length,
      exames: paciente.exames,
      examesTexto: paciente.exames.join(", "),

      linhasOriginais: paciente.linhasOriginais,

      registros: paciente.registros
    }
  });
}

return resultado;

// ======================================================
// AGRUPA PACIENTES PELO CAMPO "Paciente"
// RETORNA:
// - quantidadeExames
// - exames
// - detalhesExames
// ======================================================

const itens = $input.all().map(item => item.json);

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function numeroSeguro(valor) {
  if (valor === null || valor === undefined || valor === "") return 0;

  const n = Number(
    String(valor)
      .replace(",", ".")
      .replace(/[^\d.-]/g, "")
  );

  return Number.isFinite(n) ? n : 0;
}

const mapaPacientes = new Map();

for (const item of itens) {
  const pacienteOriginal = String(item.Paciente || "").trim();

  if (!pacienteOriginal) continue;

  const chavePaciente = normalizarTexto(pacienteOriginal);

  if (!mapaPacientes.has(chavePaciente)) {
    mapaPacientes.set(chavePaciente, {
      nomeRelatorio: item.nomeRelatorio || "",
      dataRelatorio: item.dataRelatorio || "",
      Paciente: pacienteOriginal,
      pacienteNormalizado: chavePaciente,

      quantidadeExames: 0,
      exames: [],
      detalhesExames: [],

      amostras: [],
      pedidos: [],
      lotes: [],
      eventosBag: [],

      linhasOriginais: []
    });
  }

  const paciente = mapaPacientes.get(chavePaciente);

  // ======================================================
  // CASO 1: quando existe coluna "Exame" com nome/sigla
  // Exemplo de outro relatório: Exame = "TSH"
  // ======================================================
  if (item.Exame !== undefined && item.Exame !== "") {
    const exame = String(item.Exame).trim();

    paciente.exames.push(exame);
    paciente.quantidadeExames += 1;
  }

  // ======================================================
  // CASO 2: relatório RastreioBags
  // Nele a coluna "Exames" é quantidade, não nome do exame
  // Exemplo: Exames = 1, 2, 4
  // ======================================================
  else if (item.Exames !== undefined && item.Exames !== "") {
    const qtdLinha = numeroSeguro(item.Exames);

    paciente.quantidadeExames += qtdLinha;

    paciente.exames.push(String(item.Exames).trim());
  }

  paciente.detalhesExames.push({
    amostra: item.Amostra || "",
    lote: item.Lote || "",
    conservacao: item["Conservação"] || "",
    pedido: item.Pedido || "",
    pedidoAlfanumerico: item["Pedido Alfanumérico"] || "",
    quantidadeExamesNaLinha: item.Exames ?? "",
    ultimoEventoBag: item["Último Evento da Bag"] || "",
    row_number_original: item.row_number_original || item.row_number || ""
  });

  if (item.Amostra) paciente.amostras.push(String(item.Amostra).trim());
  if (item.Pedido) paciente.pedidos.push(String(item.Pedido).trim());
  if (item.Lote) paciente.lotes.push(String(item.Lote).trim());
  if (item["Último Evento da Bag"]) paciente.eventosBag.push(String(item["Último Evento da Bag"]).trim());

  paciente.linhasOriginais.push(
    item.row_number_original || item.row_number || ""
  );
}

const resultado = [];

for (const paciente of mapaPacientes.values()) {
  resultado.push({
    json: {
      nomeRelatorio: paciente.nomeRelatorio,
      dataRelatorio: paciente.dataRelatorio,

      Paciente: paciente.Paciente,
      pacienteNormalizado: paciente.pacienteNormalizado,

      quantidadeExames: paciente.quantidadeExames,

      exames: paciente.exames,
      examesTexto: paciente.exames.join(", "),

      amostras: [...new Set(paciente.amostras)],
      pedidos: [...new Set(paciente.pedidos)],
      lotes: [...new Set(paciente.lotes)],
      eventosBag: [...new Set(paciente.eventosBag)],

      linhasOriginais: paciente.linhasOriginais,

      detalhesExames: paciente.detalhesExames
    }
  });
}

return resultado;

// ======================================================
// AJUSTA CABEÇALHO PELA LINHA 6
// DESCARTA LINHAS ANTERIORES
// ADICIONA nomeRelatorio, dataRelatorio e dataCadastro
// REMOVE ZERO À ESQUERDA DE "Convênio Sigla"
// ======================================================

const itens = $input.all().map(item => item.json);

// Nome vindo do nó If
// Exemplo: relConvDetalhadoPorLinha_13_05_2026
const nomeArquivo = $('If').first().json.name || "";

// ======================================================
// EXTRAI nomeRelatorio E dataRelatorio
// ======================================================

function extrairInfoRelatorio(nome) {
  const texto = String(nome || "").trim();

  const match = texto.match(/^(.+?)_(\d{2})_(\d{2})_(\d{4})$/);

  if (!match) {
    return {
      nomeRelatorio: texto,
      dataRelatorio: ""
    };
  }

  return {
    nomeRelatorio: match[1],
    dataRelatorio: `${match[2]}/${match[3]}/${match[4]}`
  };
}

// ======================================================
// EXTRAI APENAS A DATA
// Exemplo: "12/05/2026 06:01" -> "12/05/2026"
// ======================================================

function extrairDataCadastro(valor) {
  const texto = String(valor || "").trim();
  const match = texto.match(/\b\d{2}\/\d{2}\/\d{4}\b/);
  return match ? match[0] : "";
}

// ======================================================
// REMOVE ZERO À ESQUERDA
// Exemplo: "098" -> "98"
// Exemplo: "012" -> "12"
// Exemplo: "150" -> "150"
// ======================================================

function removerZeroEsquerda(valor) {
  const texto = String(valor ?? "").trim();

  if (!texto) return "";

  const semZeros = texto.replace(/^0+/, "");

  return semZeros || "0";
}

const { nomeRelatorio, dataRelatorio } = extrairInfoRelatorio(nomeArquivo);

// ======================================================
// LOCALIZA A LINHA 6, QUE SERÁ O CABEÇALHO
// ======================================================

const linhaCabecalho = itens.find(item => Number(item.row_number) === 6);

if (!linhaCabecalho) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Linha 6 não encontrada para montar o cabeçalho",
        nomeArquivo,
        nomeRelatorio,
        dataRelatorio
      }
    }
  ];
}

// ======================================================
// MONTA MAPA DAS COLUNAS ORIGINAIS PARA OS NOVOS NOMES
// ======================================================

const mapaCabecalho = {};

for (const [chaveOriginal, valorCabecalho] of Object.entries(linhaCabecalho)) {
  if (chaveOriginal === "row_number") continue;

  const nomeColuna = String(valorCabecalho || "").trim();

  if (!nomeColuna) continue;

  mapaCabecalho[chaveOriginal] = nomeColuna;
}

// ======================================================
// FILTRA APENAS LINHAS APÓS A LINHA 6
// ======================================================

const linhasDados = itens.filter(item => Number(item.row_number) > 6);

// ======================================================
// CONVERTE CADA LINHA USANDO O CABEÇALHO
// ======================================================

const resultado = linhasDados.map(item => {
  const dataCadastro = extrairDataCadastro(
    item["Relatório Paciente por Convênio Detalhado"]
  );

  const novoJson = {
    nomeRelatorio,
    dataRelatorio,
    dataCadastro,
    row_number_original: item.row_number
  };

  for (const [chaveOriginal, nomeColuna] of Object.entries(mapaCabecalho)) {
    let valor = item[chaveOriginal] ?? "";

    // Remove zero à esquerda apenas da coluna Convênio Sigla
    if (nomeColuna === "Convênio Sigla") {
      valor = removerZeroEsquerda(valor);
    }

    novoJson[nomeColuna] = valor;
  }

  return {
    json: novoJson
  };
});

return resultado;

// ======================================================
// AJUSTA CABEÇALHO PELA LINHA 3
// DESCARTA LINHAS ANTERIORES
// ADICIONA nomeRelatorio e dataRelatorio
// ======================================================

const itens = $input.all().map(item => item.json);

// Nome vindo do nó If
// Exemplo: RastreioBags_13052026114558
const nomeArquivo = $('If2').first().json.name || "";

// ======================================================
// EXTRAI nomeRelatorio E dataRelatorio
// Exemplo:
// RastreioBags_13052026114558
// nomeRelatorio: RastreioBags
// dataRelatorio: 13/05/2026
// ======================================================

function extrairInfoRelatorio(nome) {
  const texto = String(nome || "").trim();

  const match = texto.match(/^(.+?)_(\d{2})(\d{2})(\d{4})(\d{6})?$/);

  if (!match) {
    return {
      nomeRelatorio: texto,
      dataRelatorio: ""
    };
  }

  return {
    nomeRelatorio: match[1],
    dataRelatorio: `${match[2]}/${match[3]}/${match[4]}`
  };
}

const { nomeRelatorio, dataRelatorio } = extrairInfoRelatorio(nomeArquivo);

// ======================================================
// LOCALIZA A LINHA 3, QUE SERÁ O CABEÇALHO
// ======================================================

const linhaCabecalho = itens.find(item => Number(item.row_number) === 3);

if (!linhaCabecalho) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Linha 3 não encontrada para montar o cabeçalho",
        nomeArquivo,
        nomeRelatorio,
        dataRelatorio
      }
    }
  ];
}

// ======================================================
// MONTA MAPA DAS COLUNAS ORIGINAIS PARA OS NOVOS NOMES
// Exemplo:
// col_1 -> Amostra
// Rastreio de Bags - Geral -> Lote
// col_3 -> Conservação
// ======================================================

const mapaCabecalho = {};

for (const [chaveOriginal, valorCabecalho] of Object.entries(linhaCabecalho)) {
  if (chaveOriginal === "row_number") continue;

  const nomeColuna = String(valorCabecalho || "").trim();

  if (!nomeColuna) continue;

  mapaCabecalho[chaveOriginal] = nomeColuna;
}

// ======================================================
// FILTRA APENAS LINHAS APÓS A LINHA 3
// ======================================================

const linhasDados = itens.filter(item => Number(item.row_number) > 3);

// ======================================================
// CONVERTE CADA LINHA USANDO O CABEÇALHO
// ======================================================

const resultado = linhasDados.map(item => {
  const novoJson = {
    nomeRelatorio,
    dataRelatorio,
    row_number_original: item.row_number
  };

  for (const [chaveOriginal, nomeColuna] of Object.entries(mapaCabecalho)) {
    novoJson[nomeColuna] = item[chaveOriginal] ?? "";
  }

  return {
    json: novoJson
  };
});

return resultado;

// ======================================================
// ADICIONA ORIGEM AO INPUT 1
// Use este code depois do nó agruparNome-W
//
// Atualização:
// - Preenche dataRelatorio buscando a data no nome do arquivo:
//   $('WORKLAB').first().json.name
// - Exemplo:
//   "Relatório Worklab PARDINI bip 18-05-2026"
//   retorna "18/05/2026"
// ======================================================

const itens = $input.all();

// ======================================================
// BUSCA O NOME DO ARQUIVO NO NÓ WORKLAB
// ======================================================
const nomeArquivoWorklab = $('WORKLAB').first().json.name || "";

// ======================================================
// EXTRAI DATA DO NOME DO ARQUIVO
// Aceita:
// 18-05-2026
// 18/05/2026
// 18.05.2026
// 18_05_2026
// ======================================================
function extrairDataRelatorio(nomeArquivo) {
  const texto = String(nomeArquivo || "");

  const match = texto.match(/(\d{2})[\/\-. _](\d{2})[\/\-. _](\d{4})/);

  if (!match) return "";

  const dia = match[1];
  const mes = match[2];
  const ano = match[3];

  return `${dia}/${mes}/${ano}`;
}

const dataRelatorioWorklab = extrairDataRelatorio(nomeArquivoWorklab);

// ======================================================
// RETORNA OS ITENS COM ORIGEM E DATA DO RELATÓRIO
// ======================================================
return itens.map(item => {
  return {
    json: {
      ...item.json,
      origem: "worklab",
      dataRelatorio: item.json.dataRelatorio || dataRelatorioWorklab
    }
  };
});

// ======================================================
// ADICIONA ORIGEM AO INPUT 2
// Use este code depois do nó agruparNome-P
//
// Atualização:
// - Preenche dataRelatorio buscando a data no nome do arquivo:
//   $('PARDINI').first().json.name
// - Aceita datas como:
//   18-05-2026
//   18/05/2026
//   18.05.2026
//   18_05_2026
// - Retorna sempre no formato DD/MM/AAAA
// ======================================================

const itens = $input.all();

// ======================================================
// BUSCA O NOME DO ARQUIVO NO NÓ PARDINI
// ======================================================
const nomeArquivoPardini = $('PARDINI').first().json.name || "";

// ======================================================
// EXTRAI DATA DO NOME DO ARQUIVO
// Exemplo:
// "Relatório Pardini 18-05-2026.xlsx" -> "18/05/2026"
// ======================================================
function extrairDataRelatorio(nomeArquivo) {
  const texto = String(nomeArquivo || "");

  const match = texto.match(/(\d{2})[\/\-. _](\d{2})[\/\-. _](\d{4})/);

  if (!match) return "";

  const dia = match[1];
  const mes = match[2];
  const ano = match[3];

  return `${dia}/${mes}/${ano}`;
}

const dataRelatorioPardini = extrairDataRelatorio(nomeArquivoPardini);

// ======================================================
// RETORNA OS ITENS COM ORIGEM E DATA DO RELATÓRIO
// ======================================================
return itens.map(item => {
  return {
    json: {
      ...item.json,
      origem: "apoio",
      dataRelatorio: item.json.dataRelatorio || dataRelatorioPardini
    }
  };
});

// ======================================================
// COMPARA PACIENTES ENTRE WORKLAB E APOIO
// RETORNA APENAS matchQuantidadeExames === false
// MAS SOMENTE QUANDO O PACIENTE EXISTE NOS DOIS LADOS
// ======================================================

const itens = $input.all().map(item => item.json);

// ======================================================
// NORMALIZA TEXTO
// ======================================================
function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

// ======================================================
// CONVERTE QUANTIDADE COM SEGURANÇA
// ======================================================
function numeroSeguro(valor) {
  if (valor === null || valor === undefined || valor === "") return 0;

  const n = Number(
    String(valor)
      .replace(",", ".")
      .replace(/[^\d.-]/g, "")
  );

  return Number.isFinite(n) ? n : 0;
}

// ======================================================
// SEPARA WORKLAB E APOIO
// ======================================================
const worklab = itens.filter(item => item.origem === "worklab");
const apoio = itens.filter(item => item.origem === "apoio");

// ======================================================
// MONTA MAPA DO APOIO POR PACIENTE NORMALIZADO
// ======================================================
const mapaApoio = new Map();

for (const item of apoio) {
  const paciente = String(item.Paciente || "").trim();
  if (!paciente) continue;

  const chave = normalizarTexto(paciente);
  mapaApoio.set(chave, item);
}

const resultado = [];

// ======================================================
// COMPARA SOMENTE PACIENTES EXISTENTES NOS DOIS LADOS
// ======================================================
for (const itemWorklab of worklab) {
  const pacienteWorklab = String(itemWorklab.Paciente || "").trim();
  if (!pacienteWorklab) continue;

  const chavePaciente = normalizarTexto(pacienteWorklab);

  const itemApoio = mapaApoio.get(chavePaciente);

  if (!itemApoio) continue;

  const quantidadeExamesWorklab = numeroSeguro(itemWorklab.quantidadeExames);
  const quantidadeExamesApoio = numeroSeguro(itemApoio.quantidadeExames);

  const matchQuantidadeExames =
    quantidadeExamesWorklab === quantidadeExamesApoio;

  if (matchQuantidadeExames) continue;

  resultado.push({
    json: {
      Paciente: pacienteWorklab,
      pacienteNormalizado: chavePaciente,

      PacienteWorklab: pacienteWorklab,
      PacienteApoio: itemApoio.Paciente || "",

      existeNoWorklab: true,
      existeNoApoio: true,

      quantidadeExamesWorklab,
      quantidadeExamesApoio,
      diferencaQuantidade: quantidadeExamesWorklab - quantidadeExamesApoio,

      matchPaciente: true,
      matchQuantidadeExames: false,

      erro: true,
      tipoDivergencia: "QUANTIDADE_EXAMES_DIFERENTE",
      mensagem: "Paciente encontrado, mas a quantidade de exames está diferente",

      dadosWorklab: itemWorklab,
      dadosApoio: itemApoio
    }
  });
}

return resultado;

// ======================================================
// COMPARAR WORKLAB x PARDINI
// Retorna apenas os pacientes que DERAM MATCH
// Comparação pela chave: pacienteNormalizado
// ======================================================

// WORKLAB
const worklab = $('Code in JavaScript2').all().map(item => item.json);

// PARDINI
const pardini = $('Code in JavaScript4').all().map(item => item.json);

// ======================================================
// NORMALIZA TEXTO
// Remove acentos, espaços duplicados e deixa em maiúsculo
// ======================================================
function normalizar(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// ======================================================
// CRIA MAPA DOS PACIENTES DO PARDINI
// Chave: pacienteNormalizado normalizado
// Valor: item completo do Pardini
// ======================================================
const mapaPardini = new Map();

for (const item of pardini) {
  const nome = normalizar(item.pacienteNormalizado);

  if (nome) {
    mapaPardini.set(nome, item);
  }
}

// ======================================================
// PROCURA OS PACIENTES DO WORKLAB QUE EXISTEM NO PARDINI
// ======================================================
const matches = [];

for (const itemWorklab of worklab) {
  const nomeWorklab = normalizar(itemWorklab.pacienteNormalizado);

  if (!nomeWorklab) continue;

  const itemPardini = mapaPardini.get(nomeWorklab);

  if (itemPardini) {
    matches.push({
      pacienteNormalizado: nomeWorklab,

      matchPaciente: true,
      status: "MATCH_WORKLAB_PARDINI",

      origem1: "WORKLAB",
      dadosWorklab: itemWorklab,

      origem2: "PARDINI",
      dadosPardini: itemPardini
    });
  }
}

// ======================================================
// RETORNO FINAL
// ======================================================
return matches.map((item, index) => ({
  json: {
    ...item,
    _idx: index + 1,
    _totalMatches: matches.length
  }
}));

// ======================================================
// COMPARAR PARDINI x WORKLAB
// Retorna apenas os itens do PARDINI que NÃO existem no WORKLAB
// Comparação pela chave: pacienteNormalizado
// ======================================================

// Pega todos os itens dos dois nós
const worklab = $('Code in JavaScript2').all().map(item => item.json);
const pardini = $('Code in JavaScript4').all().map(item => item.json);

// ======================================================
// NORMALIZA TEXTO
// Remove acentos, espaços duplicados e deixa em maiúsculo
// ======================================================
function normalizar(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// ======================================================
// CRIA LISTA DE PACIENTES DO WORKLAB
// ======================================================
const pacientesWorklab = new Set(
  worklab
    .map(item => normalizar(item.pacienteNormalizado))
    .filter(nome => nome !== "")
);

// ======================================================
// FILTRA OS PACIENTES DO PARDINI QUE NÃO EXISTEM NO WORKLAB
// ======================================================
const semMatch = pardini.filter(item => {
  const pacientePardini = normalizar(item.pacienteNormalizado);
  return pacientePardini && !pacientesWorklab.has(pacientePardini);
});

// ======================================================
// RETORNO FINAL
// ======================================================
return semMatch.map((item, index) => ({
  json: {
    ...item,
    origem: "PARDINI",
    comparadoCom: "WORKLAB",
    matchPaciente: false,
    status: "SEM_MATCH_NO_WORKLAB",
    _idx: index + 1,
    _totalSemMatch: semMatch.length
  }
}));

// ======================================================
// COMPARAR WORKLAB x PARDINI
// Retorna apenas os itens do WORKLAB que NÃO existem no PARDINI
// Comparação pela chave: pacienteNormalizado
// ======================================================

// Pega todos os itens dos dois nós
const worklab = $('Code in JavaScript2').all().map(item => item.json);
const pardini = $('Code in JavaScript4').all().map(item => item.json);

// ======================================================
// NORMALIZA TEXTO
// Remove acentos, espaços duplicados e deixa em maiúsculo
// ======================================================
function normalizar(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// ======================================================
// CRIA LISTA DE PACIENTES DO PARDINI
// ======================================================
const pacientesPardini = new Set(
  pardini
    .map(item => normalizar(item.pacienteNormalizado))
    .filter(nome => nome !== "")
);

// ======================================================
// FILTRA OS PACIENTES DO WORKLAB QUE NÃO EXISTEM NO PARDINI
// ======================================================
const semMatch = worklab.filter(item => {
  const pacienteWorklab = normalizar(item.pacienteNormalizado);
  return pacienteWorklab && !pacientesPardini.has(pacienteWorklab);
});

// ======================================================
// RETORNO FINAL
// ======================================================
return semMatch.map((item, index) => ({
  json: {
    ...item,
    origem: "WORKLAB",
    comparadoCom: "PARDINI",
    matchPaciente: false,
    status: "SEM_MATCH_NO_PARDINI",
    _idx: index + 1,
    _totalSemMatch: semMatch.length
  }
}));

// ======================================================
// COMPARAR WORKLAB x PARDINI
// Retorna apenas pacientes com:
// ✅ match no pacienteNormalizado
// ❌ quantidadeExames diferente
// ======================================================

const worklab = $('Code in JavaScript2').all().map(item => item.json);
const pardini = $('Code in JavaScript4').all().map(item => item.json);

// ======================================================
// NORMALIZA NOME
// ======================================================
function normalizarNome(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// ======================================================
// NORMALIZA QUANTIDADE
// ======================================================
function normalizarQuantidade(valor) {
  const numero = Number(String(valor ?? "").replace(",", "."));
  return Number.isFinite(numero) ? numero : 0;
}

// ======================================================
// CRIA MAPA DO PARDINI PELO NOME DO PACIENTE
// ======================================================
const mapaPardini = new Map();

for (const item of pardini) {
  const nome = normalizarNome(item.pacienteNormalizado);

  if (!nome) continue;

  if (!mapaPardini.has(nome)) {
    mapaPardini.set(nome, []);
  }

  mapaPardini.get(nome).push(item);
}

// ======================================================
// COMPARA WORKLAB x PARDINI
// ======================================================
const divergentes = [];

for (const itemWorklab of worklab) {
  const nomeWorklab = normalizarNome(itemWorklab.pacienteNormalizado);

  if (!nomeWorklab) continue;

  const matchesPardini = mapaPardini.get(nomeWorklab) || [];

  for (const itemPardini of matchesPardini) {
    const qtdWorklab = normalizarQuantidade(itemWorklab.quantidadeExames);
    const qtdPardini = normalizarQuantidade(itemPardini.quantidadeExames);

    if (qtdWorklab !== qtdPardini) {
      divergentes.push({
        pacienteNormalizado: nomeWorklab,

        matchPaciente: true,
        matchQuantidadeExames: false,
        erro: true,

        tipoDivergencia: "QUANTIDADE_EXAMES_DIFERENTE",
        mensagem: "Paciente encontrado nos dois relatórios, mas a quantidade de exames é diferente",

        quantidadeExamesWorklab: qtdWorklab,
        quantidadeExamesPardini: qtdPardini,
        diferencaQuantidade: qtdWorklab - qtdPardini,

        origem1: "WORKLAB",
        dadosWorklab: itemWorklab,

        origem2: "PARDINI",
        dadosPardini: itemPardini
      });
    }
  }
}

// ======================================================
// RETORNO FINAL
// ======================================================
return divergentes.map((item, index) => ({
  json: {
    ...item,
    _idx: index + 1,
    _totalDivergentes: divergentes.length
  }
}));

// ======================================================
// COMPARAR apoioSim-WorklabNao x attic
// Retorna apenas os pacientes que estão em apoioSim-WorklabNao
// e NÃO estão em attic
//
// Chave comparada: pacienteNormalizado
// ======================================================

// ======================================================
// 1) Pega todos os itens dos dois nós
// ======================================================
const apoioSimWorklabNao = $('apoioSim-WorklabNao').all().map(item => item.json);
const attic = $('attic').all().map(item => item.json);

// ======================================================
// 2) Normaliza o nome para comparar corretamente
// Remove acentos, espaços duplicados e deixa em maiúsculo
// ======================================================
function normalizarNome(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^A-Z0-9\s]/gi, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// ======================================================
// 3) Cria uma lista de pacientes do ATTIC
// ======================================================
const pacientesAttic = new Set(
  attic
    .map(item => normalizarNome(item.pacienteNormalizado))
    .filter(nome => nome !== "")
);

// ======================================================
// 4) Filtra quem está no apoioSim-WorklabNao
// mas NÃO está no attic
// ======================================================
const semMatchNoAttic = apoioSimWorklabNao.filter(item => {
  const paciente = normalizarNome(item.pacienteNormalizado);

  if (!paciente) return false;

  return !pacientesAttic.has(paciente);
});

// ======================================================
// 5) Retorno final
// ======================================================
return semMatchNoAttic.map((item, index) => ({
  json: {
    ...item,

    pacienteNormalizado: normalizarNome(item.pacienteNormalizado),

    origem: "apoioSim-WorklabNao",
    comparadoCom: "attic",
    matchAttic: false,
    status: "NAO_EXISTE_NO_ATTIC",

    _idx: index + 1,
    _totalSemMatchNoAttic: semMatchNoAttic.length
  }
}));

// =======================================================
// LABOVIDA - Relatório de Motoqueiros OCR -> JSON
// Formato esperado:
// | Área: 1 | | Posto: 12 - CLINICA DOS FEIRANTES |
// | 18/05/2026 | 12234489 | NOME PACIENTE | EXAMES |
// =======================================================

const itensEntrada = $input.all().map(item => item.json);

// =======================================================
// 1) Pega texto OCR
// =======================================================
function obterTextoOCR(json) {
  if (!json) return "";

  if (Array.isArray(json.pages)) {
    return json.pages
      .map(page => page.markdown || page.text || "")
      .filter(Boolean)
      .join("\n");
  }

  if (json.extractedText) return String(json.extractedText);
  if (json.markdown) return String(json.markdown);
  if (json.text) return String(json.text);

  return "";
}

// =======================================================
// 2) Funções auxiliares
// =======================================================
function limparTexto(valor) {
  return String(valor || "")
    .replace(/\\n/g, "\n")
    .replace(/\\r/g, "\n")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\u00A0/g, " ")
    .replace(/[ \t]+/g, " ")
    .replace(/\n+/g, "\n")
    .trim();
}

function limparCampo(valor) {
  return String(valor || "")
    .replace(/\s+/g, " ")
    .trim();
}

function removerAcentos(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function normalizarNome(valor) {
  return removerAcentos(valor)
    .replace(/[^A-Z0-9\s]/gi, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

function normalizarExame(valor) {
  return removerAcentos(valor)
    .replace(/\s+/g, "")
    .trim()
    .toUpperCase();
}

// =======================================================
// 3) Lista de exames conhecidos
// Adicione novas siglas aqui quando precisar
// =======================================================
const EXAMES_CONHECIDOS = [
  "25OHD",
  "HB1AC",
  "COAGU",
  "URICU",
  "AATM",
  "GLIS",
  "GSRH",
  "HIV2",
  "VDRL",
  "CREA",
  "CRE",
  "CTF",
  "CTFT",
  "AUR",
  "B12",
  "CA",
  "HP",
  "SU",
  "TC",
  "TPAE",
  "TS",
  "URE",
  "TRI",
  "TSH",
  "T4L",
  "T3",
  "PCR",
  "GGT",
  "IONO",
  "VSH",
  "TGO",
  "TGP",
  "HEMO",
  "PTH",
  "EAS",
  "EPF",
  "TAP",
  "TTP",
  "TTPA",
  "INR",
  "HIV",
  "FE",
  "MG",
  "FAL",
  "BT",
  "BD",
  "BI",
  "TRIG",
  "COL",
  "HDL",
  "LDL",
  "VLDL",
  "FERRI",
  "BHCG",
  "PLAQ",
  "TPB",
  "CPK",
  "PSAT"
];

const EXAMES_ORDENADOS = [...EXAMES_CONHECIDOS].sort((a, b) => b.length - a.length);

function extrairExames(texto) {
  const s = removerAcentos(texto)
    .toUpperCase()
    .replace(/[|,;:]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const exames = [];

  // Exames com parênteses: TSH(LIB), COAGU(6)
  const regexComParen = /\b[A-Z0-9]{1,12}\s*\(\s*(?:LIB|6)\s*\)/gi;
  let match;

  while ((match = regexComParen.exec(s)) !== null) {
    const exame = normalizarExame(match[0]);
    if (!exames.includes(exame)) exames.push(exame);
  }

  // Exames sem parênteses
  for (const ex of EXAMES_ORDENADOS) {
    const re = new RegExp(`\\b${ex}\\b`, "i");

    if (re.test(s) && !exames.includes(ex)) {
      exames.push(ex);
    }
  }

  return exames;
}

function montarObjetoExames(lista) {
  const obj = {};

  lista.forEach((exame, index) => {
    obj[`ex${index + 1}`] = exame;
  });

  return obj;
}

// =======================================================
// 4) Extrai área, posto e nome do posto
// =======================================================
function extrairAreaPosto(linhas) {
  let area = null;
  let posto = null;
  let nomePosto = null;

  for (const linha of linhas) {
    if (!/Área|Area|Posto/i.test(linha)) continue;

    const linhaSemAcento = removerAcentos(linha);

    const matchArea = linhaSemAcento.match(/Area\s*:\s*(\d+)/i);
    const matchPosto = linhaSemAcento.match(/Posto\s*:\s*(\d+)\s*-\s*([^|]+)/i);

    if (matchArea) {
      area = Number(matchArea[1]);
    }

    if (matchPosto) {
      posto = Number(matchPosto[1]);
      nomePosto = limparCampo(matchPosto[2]);
    }

    if (area && posto) break;
  }

  return {
    area,
    posto,
    nomePosto
  };
}

// =======================================================
// 5) Processa todos os arquivos
// =======================================================
const todosRegistros = [];
const chavesVistas = new Set();

for (let i = 0; i < itensEntrada.length; i++) {
  const arquivo = itensEntrada[i];

  const texto = limparTexto(obterTextoOCR(arquivo));

  if (!texto) continue;

  const nomeArquivo =
    arquivo.fileName ||
    arquivo.filename ||
    arquivo.nomeArquivo ||
    arquivo.name ||
    `arquivo_${i + 1}`;

  const linhas = texto
    .split("\n")
    .map(linha => limparCampo(linha))
    .filter(Boolean);

  const dadosPosto = extrairAreaPosto(linhas);

  const area = dadosPosto.area;
  const posto = dadosPosto.posto;
  const nomePosto = dadosPosto.nomePosto;

  for (const linhaOriginal of linhas) {
    let linha = limparCampo(linhaOriginal);

    // Ignora cabeçalhos e separadores
    if (/^LABOVIDA$/i.test(linha)) continue;
    if (/Relat[oó]rio de Motoqueiros/i.test(linha)) continue;
    if (/^\|\s*-+/.test(linha)) continue;
    if (/^\|\s*---/.test(linha)) continue;
    if (/Área|Area|Posto/i.test(linha)) continue;

    // Só processa linhas de paciente:
    // | 18/05/2026 | 12234489 | NOME | EXAMES |
    if (!/^\|\s*\d{2}\/\d{2}\/\d{4}\s*\|/.test(linha)) {
      continue;
    }

    linha = linha.replace(/^\|/, "").replace(/\|$/, "").trim();

    const partes = linha
      .split("|")
      .map(p => limparCampo(p));

    if (partes.length < 4) continue;

    const dataCadastro = partes[0];
    const registroCadastro = String(partes[1] || "").replace(/\D/g, "");
    const nomePaciente = normalizarNome(partes[2]);
    const textoExames = limparCampo(partes.slice(3).join(" "));

    const examesLista = extrairExames(textoExames);

    if (!area || !posto || !dataCadastro || !registroCadastro || !nomePaciente) {
      continue;
    }

    const registro = {
      area,
      posto,
      nomePosto,
      dataCadastro,
      registroCadastro,
      nomePaciente,
      pacienteNormalizado: nomePaciente,
      exames: examesLista,
      exame: montarObjetoExames(examesLista),
      quantidadeExames: examesLista.length,
      arquivoOrigem: nomeArquivo
    };

    const chave = [
      registro.area,
      registro.posto,
      registro.dataCadastro,
      registro.registroCadastro,
      registro.pacienteNormalizado
    ].join("|");

    if (chavesVistas.has(chave)) continue;

    chavesVistas.add(chave);
    todosRegistros.push(registro);
  }
}

// =======================================================
// 6) Retorno final
// =======================================================
return todosRegistros.map((registro, index) => ({
  json: {
    ...registro,
    _idx: index + 1,
    _totalRegistros: todosRegistros.length
  }
}));
